SELECT   'logistics_rate_mismatch' AS audit_section,   x.shipment_date,   x.license_plate,   x.active_trip_count,   x.cancelled_form_count,   x.stored_high_rate_count,   GREATEST(x.active_trip_count - 3, 0) AS expected_high_rate_count,   x.stored_internal_cost,   x.expected_internal_cost FROM (   SELECT     s.shipment_date,     v.license_plate,     count(*) FILTER (WHERE s.deleted_at IS NULL) AS active_trip_count,     count(*) FILTER (WHERE s.deleted_at IS NOT NULL) AS cancelled_form_count,     count(*) FILTER (       WHERE s.deleted_at IS NULL         AND (           COALESCE(s.driver_cost, 0) > 170000 * s.driver_count           OR COALESCE(s.assistant_cost, 0) > 120000 * s.assistant_count         )     ) AS stored_high_rate_count,     COALESCE(sum(COALESCE(s.driver_cost, 0) + COALESCE(s.assistant_cost, 0)) FILTER (WHERE s.deleted_at IS NULL), 0) AS stored_internal_cost,     COALESCE(sum(       CASE         WHEN s.deleted_at IS NOT NULL THEN 0         ELSE           (CASE WHEN s.active_trip_no <= 3 THEN 170000 ELSE 230000 END) * s.driver_count           + (CASE WHEN s.active_trip_no <= 3 THEN 120000 ELSE 170000 END) * s.assistant_count       END     ), 0) AS expected_internal_cost   FROM (     SELECT       sl.*,       CASE         WHEN sl.deleted_at IS NULL THEN count(*) FILTER (WHERE sl.deleted_at IS NULL) OVER (           PARTITION BY sl.vehicle_id, sl.shipment_date           ORDER BY sl.created_at, sl.id           ROWS BETWEEN UNBOUNDED PRECEDING AND CURRENT ROW         )       END AS active_trip_no,       (CASE WHEN NULLIF(btrim(sl.driver_1_name_snapshot), '') IS NULL THEN 0 ELSE 1 END)         + (CASE WHEN NULLIF(btrim(sl.driver_2_name_snapshot), '') IS NULL THEN 0 ELSE 1 END) AS driver_count,       (CASE WHEN NULLIF(btrim(sl.assistant_1_name_snapshot), '') IS NULL THEN 0 ELSE 1 END)         + (CASE WHEN NULLIF(btrim(sl.assistant_2_name_snapshot), '') IS NULL THEN 0 ELSE 1 END) AS assistant_count     FROM public.shipment_logs sl   ) s   JOIN public.vehicles v ON v.id = s.vehicle_id AND v.type = 'nội_bộ'   GROUP BY s.shipment_date, v.license_plate ) x WHERE x.stored_high_rate_count <> GREATEST(x.active_trip_count - 3, 0)    OR x.stored_internal_cost <> x.expected_internal_cost ORDER BY x.shipment_date DESC, x.license_plate;  SELECT   'plan_actual_mismatch' AS audit_section,   p.plan_date,   p.id AS plan_id,   pr.sku,   p.actual_qty AS stored_actual_qty,   COALESCE(calc.effective_actual_qty, 0) AS calculated_actual_qty,   p.backlog_qty,   p.planned_qty FROM public.delivery_plans p JOIN public.products pr ON pr.id = p.product_id LEFT JOIN LATERAL (   SELECT COALESCE(sum(x.effective_qty), 0) AS effective_actual_qty   FROM (     SELECT       b.qty + COALESCE(sum(         CASE           WHEN a.tx_type = 'adjust_in' THEN a.qty           WHEN a.tx_type = 'adjust_out' THEN -a.qty           ELSE 0         END       ), 0) AS effective_qty     FROM public.inventory_transactions b     LEFT JOIN public.inventory_transactions a       ON a.adjusted_from_transaction_id = b.id      AND a.deleted_at IS NULL      AND a.tx_type IN ('adjust_in', 'adjust_out')     WHERE b.delivery_plan_id = p.id       AND b.tx_type = 'out'       AND b.adjusted_from_transaction_id IS NULL       AND b.deleted_at IS NULL     GROUP BY b.id, b.qty   ) x ) calc ON true WHERE p.deleted_at IS NULL   AND COALESCE(p.actual_qty, 0) <> COALESCE(calc.effective_actual_qty, 0) ORDER BY p.plan_date DESC, pr.sku;  SELECT   'duplicate_live_backlog_key' AS audit_section,   p.plan_date,   p.product_id,   public.delivery_point_key(p.customer_id, p.delivery_customer_id) AS delivery_point_key,   count(*) AS row_count FROM public.delivery_plans p WHERE p.deleted_at IS NULL   AND COALESCE(p.backlog_qty, 0) > 0 GROUP BY   p.plan_date,   p.product_id,   public.delivery_point_key(p.customer_id, p.delivery_customer_id) HAVING count(*) > 1 ORDER BY p.plan_date DESC;
